noncompliant:
// Template parameter referenced but not named - Noncompliant
auto lambda = []<typename>(auto a, auto b) {
    return std::pair{a, b}; // Same type used multiple times
};

// Function template with unnamed but referenced parameter
template<typename>
void process(auto value1, auto value2) {
    // Both parameters should be same type but this is not clear
}

compliant:
// Properly named template parameter - Compliant
auto lambda = []<typename T>(T a, T b) {
    return std::pair<T, T>{a, b};
};

// Function template with named parameter
template<typename T>
void process(T value1, T value2) {
    // Clear that both parameters are of same type T
}
